+fn push_var_declarator_segment<'a>(
+    out: &mut Vec<&'a str>,
+    source: &'a str,
+    start: usize,
+    end: usize,
+) {
+    if end < start {
+        return;
+    }
+    let raw = &source[start..end];
+    let trimmed = raw.trim();
+    if trimmed.is_empty() {
+        return;
+    }
+    out.push(trimmed);
+}
